INSERT INTO reviews (id, book_id, rating, review, created_at, updated_at) VALUES
                                                                              ('d1000000-0000-0000-0000-000000000001', 'c1000000-0000-0000-0000-000000000001', 5, 'One of the most chilling and prescient novels ever written.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000002', 'c1000000-0000-0000-0000-000000000001', 4, 'Deeply unsettling and absolutely essential reading.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000003', 'c1000000-0000-0000-0000-000000000002', 4, 'A brilliant political allegory that still feels relevant today.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000004', 'c1000000-0000-0000-0000-000000000002', 5, 'Short but devastating. Orwell at his finest.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000005', 'c1000000-0000-0000-0000-000000000003', 5, 'An absolute masterpiece of world-building.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000006', 'c1000000-0000-0000-0000-000000000003', 5, 'Dense but rewarding. One of the greatest sci-fi novels ever.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000007', 'c1000000-0000-0000-0000-000000000004', 4, 'Not as good as Dune but still a worthwhile read.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000008', 'c1000000-0000-0000-0000-000000000004', 3, 'Felt a bit slow compared to the first book.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000009', 'c1000000-0000-0000-0000-000000000005', 5, 'A perfect adventure. Timeless and wonderful.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000010', 'c1000000-0000-0000-0000-000000000005', 5, 'Magical from start to finish. Tolkien is unmatched.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000011', 'c1000000-0000-0000-0000-000000000006', 5, 'The greatest fantasy novel ever written. Period.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000012', 'c1000000-0000-0000-0000-000000000006', 5, 'An immense achievement. Changed fantasy forever.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000013', 'c1000000-0000-0000-0000-000000000007', 5, 'The twist is still one of the best in mystery fiction.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000014', 'c1000000-0000-0000-0000-000000000007', 4, 'Christie at her most clever. Superb plotting.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000015', 'c1000000-0000-0000-0000-000000000008', 5, 'Impossibly tense. Could not put it down.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000016', 'c1000000-0000-0000-0000-000000000008', 4, 'Christie''s best work in my opinion.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000017', 'c1000000-0000-0000-0000-000000000009', 5, 'The scariest book I have ever read. King is a genius.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000018', 'c1000000-0000-0000-0000-000000000009', 4, 'Slow burn terror done to perfection.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000019', 'c1000000-0000-0000-0000-000000000010', 4, 'Massive but never boring. King''s magnum opus.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000020', 'c1000000-0000-0000-0000-000000000010', 4, 'Pennywise is the most terrifying villain in fiction.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000021', 'c1000000-0000-0000-0000-000000000011', 5, 'The birth of modern science fiction. Essential.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000022', 'c1000000-0000-0000-0000-000000000011', 4, 'Asimov''s ideas are still mind-blowing decades later.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000023', 'c1000000-0000-0000-0000-000000000012', 4, 'Thought-provoking exploration of gender and identity.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000024', 'c1000000-0000-0000-0000-000000000012', 4, 'Le Guin''s prose is beautiful and her ideas profound.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000025', 'c1000000-0000-0000-0000-000000000013', 4, 'A fascinating thought experiment about society and freedom.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000026', 'c1000000-0000-0000-0000-000000000013', 4, 'Dense and philosophical but hugely rewarding.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000027', 'c1000000-0000-0000-0000-000000000014', 5, 'The funniest book in the universe. Literally.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000028', 'c1000000-0000-0000-0000-000000000014', 5, 'Adams''s wit is unmatched. A comedy masterpiece.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000029', 'c1000000-0000-0000-0000-000000000015', 4, 'A worthy conclusion to the trilogy. Mostly harmless.', NOW(), NOW()),
                                                                              ('d1000000-0000-0000-0000-000000000030', 'c1000000-0000-0000-0000-000000000015', 4, 'Not as strong as the first but Adams''s humor still shines.', NOW(), NOW());
